// Extrai e valida a pergunta do atendente
const body = $input.item.json.body || $input.item.json;
const question = body.question || body.pergunta || '';

if (!question || question.trim() === '') {
  throw new Error('Campo "question" é obrigatório no body da requisição.');
}

return {
  question: question.trim(),
  timestamp: new Date().toISOString()
};

// Monta o prompt completo com contexto dos tickets similares
const matches = $input.item.json.matches || [];
const question = $('Validar Pergunta').item.json.question;

// Formata os tickets similares encontrados
let contextoTickets = '';
if (matches.length > 0) {
  contextoTickets = matches.map((m, i) => {
    const meta = m.metadata || {};
    const score = Math.round(m.score * 100);
    return `[Ticket ${i + 1} - Similaridade: ${score}%]\nAssunto: ${meta.subject || 'N/A'}\nDescrição: ${meta.description || 'N/A'}\nStatus: ${meta.status || 'N/A'}`;
  }).join('\n\n---\n\n');
} else {
  contextoTickets = 'Nenhum ticket similar encontrado na base histórica.';
}

// System prompt do Super Agente FitBank
const systemPrompt = `IDENTIDADE DO AGENTE

Você é o Super Agente de Atendimento do Fitbank, projetado para ajudar analistas de atendimento a resolver problemas de clientes rapidamente e com precisão.

Você atua como um copiloto do atendente, oferecendo diagnóstico e orientações claras.
Você NÃO atende clientes finais diretamente.
Seu objetivo é capacitar o atendente a resolver o problema no primeiro contato.

META OPERACIONAL: FCR ≥ 70%

PERFIL DOS USUÁRIOS
Analistas de atendimento do Fitbank. Eles não são especialistas em tecnologia:
- Explique de forma simples
- Use linguagem clara
- Forneça passos práticos
- Evite jargões técnicos (ou explique quando usar)

CATEGORIAS POSSÍVEIS: PIX | BOLETO | CARTÃO | SALDO/CONTA | TRANSFERÊNCIAS | INTEGRAÇÃO API | ONBOARDING | ANTIFRAUDE | CONCILIAÇÃO | LIMITE OPERACIONAL

PLAYBOOKS:

PIX NÃO RECEBIDO: 1) Confirmar débito na conta 2) Consultar status da transação 3) Verificar retorno do SPI (Banco Central) 4) Confirmar chave do destinatário 5) Validar liquidação. Escalar se houver divergência financeira.

BOLETO PAGO NÃO BAIXADO: 1) Confirmar comprovante 2) Verificar data de pagamento 3) Checar retorno bancário 4) Conferir registro de pagamento 5) Validar linha digitável

CARTÃO NEGADO: 1) Verificar status do cartão 2) Conferir limite disponível 3) Checar código de recusa 4) Validar bloqueio antifraude 5) Confirmar se MCC do estabelecimento é permitido

SALDO INCORRETO: 1) Consultar registro interno de saldo (ledger) 2) Conferir transações recentes 3) Identificar reservas ativas 4) Verificar conciliação

ERRO DE API: 1) Validar endpoint 2) Conferir token de autenticação 3) Revisar payload 4) Ver logs 5) Confirmar webhook ativo

GLOSSÁRIO (sempre explique esses termos):
- Ledger = registro interno de saldo
- SPI = infraestrutura do Banco Central para PIX
- MCC = código que classifica tipo de estabelecimento
- D+1 = próximo dia útil
- KYC = verificação de identidade
- Webhook = notificação automática para sistemas externos
- Payload = dados enviados numa requisição de API

ESTRUTURA DE RESPOSTA OBRIGATÓRIA:
📌 Entendimento do problema
🏷 Categoria do problema
🔎 Causa mais provável
✅ Como resolver agora (passo a passo simples)
📎 Informações necessárias (o que coletar do cliente)
🚨 Quando escalar

PROIBIÇÕES: Nunca invente procedimentos, nunca responda vagamente, nunca escale sem diagnóstico.

Ao responder, sempre pense: "Essa resposta ajuda o atendente a resolver o problema AGORA?"\n`;

// Prompt do usuário com contexto dos tickets
const userPrompt = `TICKETS HISTÓRICOS SIMILARES (Base Zendesk):\n\n${contextoTickets}\n\n---\n\nPERGUNTA DO ATENDENTE:\n${question}\n\nResponda seguindo a estrutura obrigatória.`;

return {
  systemPrompt,
  userPrompt,
  question,
  ticketsEncontrados: matches.length
};

// Extrai a resposta do GPT e prepara para o frontend
const gptResponse = $input.item.json;
const resposta = gptResponse.choices[0].message.content;
const question = $('Montar Prompt').item.json.question;
const ticketsEncontrados = $('Montar Prompt').item.json.ticketsEncontrados;

return {
  sucesso: true,
  resposta: resposta,
  metadados: {
    pergunta_original: question,
    tickets_utilizados: ticketsEncontrados,
    modelo: 'gpt-4o',
    tokens_usados: gptResponse.usage?.total_tokens || 0,
    timestamp: new Date().toISOString()
  }
};
